import React from 'react';

export default function Footer() {
  return (
    <footer style={{ textAlign: 'center', padding: '2.5rem 5%', borderTop: '1px solid rgba(201,168,76,0.1)', color: '#8892a4', fontSize: '0.85rem', background: '#0a1628' }}>
      <p>Crafted with ♥ by <span style={{ color: '#c9a84c' }}>Deva Princy J</span> · Thoothukudi, Tamil Nadu · 2026</p>
    </footer>
  );
}
